Prolog:
sPrefix = Trim(pPrefix);
If(sPrefix @= '');
  sPrefix = 'IMF';
EndIf;

sDimensionCode = Trim(pDimensionCode);
sVersionId = Trim(pVersionId);
sSourceVersion = Trim(pSourceVersion);
sCreatedBy = Trim(pCreatedBy);

If(sCreatedBy @= '');
  sCreatedBy = 'SYSTEM';
EndIf;

sDimVersion = sPrefix | '.D.Version';
sCubeVersion = sPrefix | '.C.Version';

If(DimensionElementExists(sDimVersion, sVersionId) = 0);
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimVersion, sSourceVersion) = 0);
  ProcessBreak;
EndIf;
If(CellGetS(sCubeVersion, sSourceVersion, 'DimensionCode') @<> sDimensionCode);
  ProcessBreak;
EndIf;

sSourceWorkDimension = Trim(CellGetS(sCubeVersion, sSourceVersion, 'WorkDimension'));
sTargetWorkDimension = Trim(CellGetS(sCubeVersion, sVersionId, 'WorkDimension'));
If(sSourceWorkDimension @= '');
  ProcessBreak;
EndIf;
If(sTargetWorkDimension @= '');
  ProcessBreak;
EndIf;
If(DimensionExists(sSourceWorkDimension) = 0);
  ProcessBreak;
EndIf;

If(DimensionExists(sTargetWorkDimension) = 0);
  DimensionCreate(sTargetWorkDimension);
EndIf;

ExecuteProcess(sPrefix | '.P.Dimension.CopyAll',
  'pPrefix', sPrefix,
  'pSourceDimension', sSourceWorkDimension,
  'pTargetDimension', sTargetWorkDimension,
  'pIncludeData', 'N');

CellPutS('VERSION', sCubeVersion, sVersionId, 'SourceType');
CellPutS(sSourceVersion, sCubeVersion, sVersionId, 'SourceVersion');
CellPutS('Draft', sCubeVersion, sVersionId, 'Status');
CellPutS('Version clone initialized from ' | sSourceVersion | ' and routed through IMF.P.Dimension.CopyAll.', sCubeVersion, sVersionId, 'Notes');

AttrPutS('VERSION', sDimVersion, sVersionId, 'SourceType');
AttrPutS(sSourceVersion, sDimVersion, sVersionId, 'SourceVersion');
AttrPutS('Draft', sDimVersion, sVersionId, 'Status');
AttrPutS('Version clone initialized from ' | sSourceVersion | ' and routed through IMF.P.Dimension.CopyAll.', sDimVersion, sVersionId, 'Notes');
